import{_ as s,C as l,o as n,c as o,E as r,w as a,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Greece Healthcare & HRT","description":"Transgender healthcare access in Greece","frontmatter":{"layout":"doc","title":"Greece Healthcare & HRT","description":"Transgender healthcare access in Greece"},"headers":[],"relativePath":"europe/greece/healthcare.md","filePath":"europe/greece/healthcare.md","lastUpdated":null}'),c={name:"europe/greece/healthcare.md"};function h(p,e,u,g,m,b){const t=l("Badge");return n(),o("div",null,[r(t,{variant:"yellow"},{default:a(()=>[...e[0]||(e[0]=[i("Gatekeeping Model",-1)])]),_:1}),r(t,{variant:"yellow"},{default:a(()=>[...e[1]||(e[1]=[i("Limited Clinics",-1)])]),_:1}),r(t,{variant:"green"},{default:a(()=>[...e[2]||(e[2]=[i("Public Healthcare Coverage",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="healthcare-hrt-in-greece" tabindex="-1">Healthcare &amp; HRT in Greece <a class="header-anchor" href="#healthcare-hrt-in-greece" aria-label="Permalink to &quot;Healthcare &amp; HRT in Greece&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Greece operates a <strong>gatekeeping model</strong> for transgender healthcare:</p><ul><li><strong>Psychiatric diagnosis required</strong> to access HRT</li><li>Assessment at specialized Gender Identity Clinics</li><li>Treatment monitored by a multidisciplinary team</li><li>Process varies between public and private sectors</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-referral" tabindex="-1">Step 1: Referral <a class="header-anchor" href="#step-1-referral" aria-label="Permalink to &quot;Step 1: Referral&quot;">​</a></h3><ul><li>Obtain a referral from a GP or directly contact a Gender Identity Clinic</li><li>The main public clinic is at <strong>Alexandras General Hospital</strong> in Athens</li><li>Thessaloniki has limited services at AHEPA Hospital</li></ul><h3 id="step-2-psychiatric-assessment" tabindex="-1">Step 2: Psychiatric Assessment <a class="header-anchor" href="#step-2-psychiatric-assessment" aria-label="Permalink to &quot;Step 2: Psychiatric Assessment&quot;">​</a></h3><ul><li>Diagnosis of gender dysphoria per ICD-10/11</li><li>Psychological evaluation over 3-6 sessions</li><li>Family support assessment may be included</li></ul><h3 id="step-3-hormone-therapy" tabindex="-1">Step 3: Hormone Therapy <a class="header-anchor" href="#step-3-hormone-therapy" aria-label="Permalink to &quot;Step 3: Hormone Therapy&quot;">​</a></h3><ul><li>Referral to an endocrinologist after diagnosis</li><li>Baseline blood tests and physical examination</li><li>HRT prescribed under medical supervision</li><li>Follow-up every 3-6 months</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Alexandras General Hospital</td><td>Athens</td><td>Multidisciplinary gender clinic (public)</td></tr><tr><td>AHEPA University Hospital</td><td>Thessaloniki</td><td>Limited gender services (public)</td></tr><tr><td>Private endocrinologists</td><td>Athens, Thessaloniki</td><td>HRT (shorter wait times)</td></tr><tr><td>IASIS Clinic</td><td>Athens</td><td>Private gender-affirming care</td></tr><tr><td>Metropolitan Hospital</td><td>Athens</td><td>Private surgical options</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Greece under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be evaluated and re-prescribed by a Greek doctor</li><li><strong>Carrying medication</strong>: 90-day supply permitted with a doctor&#39;s letter</li><li><strong>Keep medication in original packaging</strong> with pharmacy labels</li><li><strong>Know generic/brand names</strong>: Estrofem (estradiol), Androcur (cyproterone), Testogel (testosterone)</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li>Gender-affirming surgeries are <strong>covered by public healthcare</strong> (EFKA) with prior authorization</li><li>Surgery requires referral from an authorized gender clinic</li><li>Public wait times: 12-24 months for consultation, 18-36 months for surgery</li><li>Private surgery: €5,000-15,000 depending on procedure</li><li>Popular destinations: Athens, Thessaloniki, or abroad (Thailand, Spain, Serbia)</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Public (insured)</th><th>Private</th></tr></thead><tbody><tr><td>Psychiatric assessment</td><td>Free</td><td>€80-150</td></tr><tr><td>Endocrinology visit</td><td>Free</td><td>€60-120</td></tr><tr><td>HRT (monthly)</td><td>€5-25</td><td>€25-60</td></tr><tr><td>Gender clinic assessment</td><td>Free</td><td>€150-300</td></tr><tr><td>Top surgery</td><td>Covered (public)</td><td>€4,000-8,000</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.gen-nosokomeio-athinon.gr/" target="_blank" rel="noreferrer">Alexandras General Hospital</a></li><li><a href="https://www.moh.gov.gr/" target="_blank" rel="noreferrer">Greek Ministry of Health</a></li><li><a href="https://www.efka.gov.gr/" target="_blank" rel="noreferrer">EFKA (National Insurance)</a></li><li><a href="https://www.synthesis.gr/" target="_blank" rel="noreferrer">SYNTHESI (Trans Support)</a></li></ul>',21))])}const P=s(c,[["render",h]]);export{f as __pageData,P as default};
